export const getAllCountries = (): { code: string; name: string }[] => {
  return countriesAndStates.map(country => ({
    code: country.code,
    name: country.name,
  }));
};

export const getStatesByCountry = (countryName: string): string[] => {
  const country = countriesAndStates.find(c => c.name === countryName);
  return country ? country.states : [];
};
